def interactive_demo():
    """Interactive demonstration of the TOTP MFA system."""
    auth = TOTPAuthenticator()

    while True:
        print("\n" + "=" * 50)
        print("  TOTP Two-Factor Authentication System")
        print("=" * 50)
        print("1. Register new user")
        print("2. Verify TOTP code")
        print("3. Show current code (testing)")
        print("4. List users")
        print("5. Reset user secret")
        print("6. Remove user")
        print("7. Show time remaining")
        print("8. Run automated tests")
        print("9. Exit")
        print("-" * 50)

        choice = input("Select option: ").strip()

        if choice == '1':
            username = input("Enter username: ").strip()
            issuer = input("Enter issuer name (default: MFASystem): ").strip() or "MFASystem"
            try:
                result = auth.register_user(username, issuer)
                print(f"\n✅ User '{username}' registered successfully!")
                print(f"Secret: {result['secret']}")
                print(f"Provisioning URI: {result['provisioning_uri']}")
                if result['qr_code_path']:
                    print(f"QR Code: {result['qr_code_path']}")
                print(f"\nBackup codes (save these securely):")
                for i, code in enumerate(result['backup_codes'], 1):
                    print(f"  {i}. {code}")
                print(f"\nScan the QR code with your authenticator app (Google Authenticator, Authy, etc.)")
            except ValueError as e:
                print(f"❌ Error: {e}")

        elif choice == '2':
            username = input("Enter username: ").strip()
            code = input("Enter TOTP code: ").strip()
            try:
                if auth.verify_user(username, code):
                    print(f"✅ Code verified successfully for '{username}'!")
                else:
                    print(f"❌ Invalid code for '{username}'.")
            except ValueError as e:
                print(f"❌ Error: {e}")

        elif choice == '3':
            username = input("Enter username: ").strip()
            try:
                code = auth.get_current_code(username)
                remaining = auth.get_remaining_time()
                print(f"Current TOTP code for '{username}': {code}")
                print(f"Valid for {remaining} more seconds")
            except ValueError as e:
                print(f"❌ Error: {e}")

        elif choice == '4':
            users = auth.list_users()
            if not users:
                print("No users registered.")
            else:
                print(f"\nRegistered users ({len(users)}):")
                for user in users:
                    status = "✅ Verified" if user['verified'] else "⏳ Pending"
                    print(f"  - {user['username']} ({user['issuer']}) [{status}] "
                          f"Backup codes: {user['backup_codes_remaining']}")

        elif choice == '5':
            username = input("Enter username: ").strip()
            issuer = input("Enter issuer name (default: MFASystem): ").strip() or "MFASystem"
            result = auth.reset_user(username, issuer)
            print(f"✅ Secret reset for '{username}'.")
            print(f"New secret: {result['secret']}")

        elif choice == '6':
            username = input("Enter username: ").strip()
            if auth.remove_user(username):
                print(f"✅ User '{username}' removed.")
            else:
                print(f"❌ User '{username}' not found.")

        elif choice == '7':
            remaining = auth.get_remaining_time()
            print(f"⏱️  {remaining} seconds remaining in current time step")

        elif choice == '8':
            run_tests()

        elif choice == '9':
            print("Goodbye!")
            break

        else:
            print("Invalid option. Please try again.")


